// Obyektdə this nümunəsi
let chef = {
  name: "Aysel",
  dish: "Omlet",
  cook: function() {
    return this.name + " " + this.dish + " hazırlayır!";
  }
};
console.log(chef.cook()); // nəticə: Aysel Omlet hazırlayır!

// Fərqli kontekstlərdə this
let chef = {
  name: "Aysel",
  cook: function() {
    console.log(this.name + " yemək hazırlayır!");
  }
};
chef.cook(); // nəticə: Aysel yemək hazırlayır!

function cookBreakfast() {
  console.log(this); // nəticə: window (brauzerdə)
}
cookBreakfast();

// this-in kontekst dəyişikliyi
let chef1 = { name: "Aysel", cook: function() { return this.name; } };
let chef2 = { name: "Elvin" };
let cookFunction = chef1.cook;
console.log(cookFunction()); // nəticə: undefined (this window-a işarə edir)
console.log(cookFunction.call(chef2)); // nəticə: Elvin (this chef2-yə dəyişdirilib)

// Event listener-də this
let button = document.createElement("button");
button.textContent = "Kliklə!";
button.addEventListener("click", function() {
  console.log(this); // nəticə: button elementi
});
document.body.appendChild(button);

// Konstruktor funksiyada this
function Chef(name) {
  this.name = name;
  this.cook = function() {
    return this.name + " yemək hazırlayır!";
  };
}
let newChef = new Chef("Kamran");
console.log(newChef.cook()); // nəticə: Kamran yemək hazırlayır!

// this ilə səhv kontekst
let chef = {
  name: "Aysel",
  cook: function() {
    console.log(this.name);
  }
};
let cookFn = chef.cook;
cookFn(); // nəticə: undefined (this window-a işarə edir)

// bind ilə düzəliş
let boundCook = chef.cook.bind(chef);
boundCook(); // nəticə: Aysel

