// this in an object
let chef = {
  name: "Aysel",
  dish: "Omelette",
  cook: function() {
    return this.name + " is cooking " + this.dish + "!";
  }
};
console.log(chef.cook()); // Output: Aysel is cooking Omelette!

// this in different contexts
let chef = {
  name: "Aysel",
  cook: function() {
    console.log(this.name + " is cooking!");
  }
};
chef.cook(); // Output: Aysel is cooking!

function cookBreakfast() {
  console.log(this); // Output: window (in browsers)
}
cookBreakfast();

// this context change
let chef1 = { name: "Aysel", cook: function() { return this.name; } };
let chef2 = { name: "Elvin" };
let cookFunction = chef1.cook;
console.log(cookFunction()); // Output: undefined (this refers to window)
console.log(cookFunction.call(chef2)); // Output: Elvin (this set to chef2)

// this in an event listener
let button = document.createElement("button");
button.textContent = "Click me!";
button.addEventListener("click", function() {
  console.log(this); // Output: button element
});
document.body.appendChild(button);

// this in a constructor function
function Chef(name) {
  this.name = name;
  this.cook = function() {
    return this.name + " is cooking!";
  };
}
let newChef = new Chef("Kamran");
console.log(newChef.cook()); // Output: Kamran is cooking!

// this with wrong context
let chef = {
  name: "Aysel",
  cook: function() {
    console.log(this.name);
  }
};
let cookFn = chef.cook;
cookFn(); // Output: undefined (this refers to window)

// Fixing with bind
let boundCook = chef.cook.bind(chef);
boundCook(); // Output: Aysel

