// this в объекте
let chef = {
  name: "Айсель",
  dish: "Омлет",
  cook: function() {
    return this.name + " готовит " + this.dish + "!";
  }
};
console.log(chef.cook()); // Вывод: Айсель готовит Омлет!

// this в разных контекстах
let chef = {
  name: "Айсель",
  cook: function() {
    console.log(this.name + " готовит!");
  }
};
chef.cook(); // Вывод: Айсель готовит!

function cookBreakfast() {
  console.log(this); // Вывод: window (в браузерах)
}
cookBreakfast();

// Изменение контекста this
let chef1 = { name: "Айсель", cook: function() { return this.name; } };
let chef2 = { name: "Эльвин" };
let cookFunction = chef1.cook;
console.log(cookFunction()); // Вывод: undefined (this ссылается на window)
console.log(cookFunction.call(chef2)); // Вывод: Эльвин (this изменён на chef2)

// this в обработчике событий
let button = document.createElement("button");
button.textContent = "Нажми меня!";
button.addEventListener("click", function() {
  console.log(this); // Вывод: элемент button
});
document.body.appendChild(button);

// this в функции-конструкторе
function Chef(name) {
  this.name = name;
  this.cook = function() {
    return this.name + " готовит!";
  };
}
let newChef = new Chef("Кямран");
console.log(newChef.cook()); // Вывод: Кямран готовит!

// this с неправильным контекстом
let chef = {
  name: "Айсель",
  cook: function() {
    console.log(this.name);
  }
};
let cookFn = chef.cook;
cookFn(); // Вывод: undefined (this ссылается на window)

// Исправление с помощью bind
let boundCook = chef.cook.bind(chef);
boundCook(); // Вывод: Айсель

